 $(document).ready(function() {
      const tooltipTriggerList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));
      tooltipTriggerList.map(function(tooltipTriggerEl) {
        return new bootstrap.Tooltip(tooltipTriggerEl, { delay: { "show": 300, "hide": 100 } });
      });
      const deleteModal = new bootstrap.Modal(document.getElementById('deleteConfirmationModal'));

      $('.password-input').on('input', function() {
        $(this).siblings('.toggle-password-button').css('display', $(this).val().length > 0 ? 'inline-flex' : 'none');
      });

      $('.toggle-password-button').on('click', function() {
        const input = $(this).siblings('input.password-input');
        const eye = $(this).find('.fa-eye');
        const eyeSlash = $(this).find('.fa-eye-slash');
        if (input.attr('type') === 'password') {
          input.attr('type', 'text');
          eyeSlash.hide();
          eye.show();
        } else {
          input.attr('type', 'password');
          eyeSlash.show();
          eye.hide();
        }
      });

      const urlParams = new URLSearchParams(window.location.search);
      const tabParam = urlParams.get('tab');
      if (tabParam) {
        const tabLink = document.querySelector(`#${tabParam}-tab-link`);
        if (tabLink) new bootstrap.Tab(tabLink).show();
      } else {
        new bootstrap.Tab($('#profile-tab-link')[0]).show();
      }

      $('#image-upload-input').on('change', function(e) {
        if (e.target.files[0]) {
          const reader = new FileReader();
          reader.onload = (ev) => $('#display-image').attr('src', ev.target.result);
          reader.readAsDataURL(e.target.files[0]);
          $('#profile-details-form').submit();
        }
      });

      const validationConfig = {
          errorElement: 'div',
          errorClass: 'invalid-feedback',
          highlight: function(element, errorClass, validClass) {
              $(element).addClass('is-invalid');
          },
          unhighlight: function(element, errorClass, validClass) {
              $(element).removeClass('is-invalid');
          },
          errorPlacement: function(error, element) {
              if (element.parent('.input-group').length) {
                  error.insertAfter(element.parent());
              } else {
                  error.insertAfter(element);
              }
          }
      };

      $('#profile-details-form').validate({
        ...validationConfig,
        rules: {
            username: { required: true },
            email: { required: true, email: true },
            phone: { required: true }
        },
        messages: {
            username: "Please enter your username.",
            email: "Please enter a valid email address.",
            phone: "Please provide your phone number."
        },
        submitHandler: function(form) {
          const btn = $(form).find('button[type="submit"]');
          btn.prop('disabled', true).html('<span class="spinner-border spinner-border-sm"></span> Updating...');
          $.ajax({
            url: 'ajax/profile_handler.php',
            type: 'POST',
            data: new FormData(form),
            processData: false,
            contentType: false,
            dataType: 'json',
            success: function(res) {
              if (res.success) {
                toastr.success(res.message);
                $('#display-username').text(res.newData.username);
                $('#display-email').text(res.newData.email);
                $('#display-phone').text($(form).find('input[name="phone"]').val());
                $('.dropdown-menu .dropdown-item.bg-secondary-subtle .flex-grow-1 h6').text(res.newData.username);
                if (res.newData.image) {
                  const newPath = 'images/' + res.newData.image + '?t=' + new Date().getTime();
                  $('#display-image, .header-profile-image').attr('src', newPath);
                  $('input[name="oldimage"]').val(res.newData.image);
                }
                $('#image-upload-input').val('');
              } else {
                toastr.error(res.message || 'An error occurred.');
              }
            },
            error: () => toastr.error('A server error occurred.'),
            complete: () => btn.prop('disabled', false).html('Update Profile')
          });
        }
      });

      $('#password-form').validate({
        ...validationConfig,
        rules: {
          current_password: { required: true },
          new_password: { required: true, minlength: 5 },
          confirm_password: { required: true, minlength: 5, equalTo: "#new_password" }
        },
        messages: {
            current_password: "Please enter your current password.",
            new_password: {
                required: "Please provide a new password.",
                minlength: "Your password must be at least 5 characters long."
            },
            confirm_password: {
                required: "Please confirm your new password.",
                minlength: "Your password must be at least 5 characters long.",
                equalTo: "Please enter the same password as above."
            }
        },
        submitHandler: function(form) {
          const btn = $(form).find('button[type="submit"]');
          btn.prop('disabled', true).html('<span class="spinner-border spinner-border-sm"></span> Changing...');
          $.post('ajax/profile_handler.php', $(form).serialize(), (res) => {
            if (res.success) {
              toastr.success(res.message);
              form.reset();
              $('.toggle-password-button').hide();
              $(form).find('.is-invalid').removeClass('is-invalid');
              $(form).find('.invalid-feedback').remove();
            } else {
              toastr.error(res.message);
            }
          }, 'json').fail(() => toastr.error('Server error.')).always(() => btn.prop('disabled', false).html('Change Password'));
        }
      });

      function updateClock() {
        const now = new Date();
        const options = { timeZone: 'Asia/Kolkata', hour12: true, hour: '2-digit', minute: '2-digit', second: '2-digit' };
        const dateOptions = { timeZone: 'Asia/Kolkata', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
        $('#clock-time').text(now.toLocaleTimeString('en-US', options));
        $('#clock-date').text(now.toLocaleDateString('en-GB', dateOptions));
      }
      setInterval(updateClock, 1000);
      updateClock();

      let allBackups = [], allRecycled = [], currentSort = { column: 'modified', direction: 'desc' }, backupChart;

      const formatBytes = (b, d = 2) => {
        if (b === 0) return "0 Bytes";
        const k = 1024, s = ["Bytes", "KB", "MB", "GB"], i = Math.floor(Math.log(b) / Math.log(k));
        return parseFloat((b / Math.pow(k, i)).toFixed(d < 0 ? 0 : d)) + " " + s[i];
      };

      const formatDate = (t) => {
        const d = new Date(t * 1000);
        return d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }) + ' ' +
               d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true });
      };

      const renderTable = (data, tableId) => {
        const tbody = $(`#${tableId} tbody`), searchTerm = $('#db-search').val().toLowerCase();
        tbody.empty();
        data.sort((a, b) => {
          let vA = a[currentSort.column], vB = b[currentSort.column];
          if (currentSort.column === 'name') {
            vA = vA.toLowerCase();
            vB = vB.toLowerCase();
          }
          return currentSort.direction === 'desc' ? (vB > vA ? 1 : -1) : (vA > vB ? 1 : -1);
        });
        const filteredData = data.filter(f => `${f.name} ${formatBytes(f.size)} ${formatDate(f.modified)}`.toLowerCase().includes(searchTerm));
        if (filteredData.length === 0) {
          tbody.append(`<tr><td colspan="6" class="text-center text-muted py-4">No files found.</td></tr>`);
          return;
        }

        filteredData.forEach((file, index) => {
          const isRecycled = tableId.includes('recycled');
          const actions = isRecycled
            ? `<button class="btn btn-sm btn-outline-info restore-btn" data-filename="${file.name}" data-bs-toggle="tooltip" title="Restore"><i class="las la-undo"></i></button>
               <button class="btn btn-sm btn-outline-danger perm-delete-btn" data-filename="${file.name}" data-bs-toggle="tooltip" title="Delete Permanently"><i class="las la-times-circle"></i></button>`
            : `<button class="btn btn-sm btn-outline-secondary view-btn" data-filename="${file.name}" data-bs-toggle="tooltip" title="View SQL Content"><i class="las la-eye"></i></button>
               <a href="database/backup/${file.name}" class="btn btn-sm btn-outline-success" data-bs-toggle="tooltip" title="Download Backup" download><i class="las la-download"></i></a>
               <button class="btn btn-sm btn-outline-warning delete-btn" data-filename="${file.name}" data-bs-toggle="tooltip" title="Delete"><i class="las la-trash"></i></button>`;
          const row = `<tr data-filename="${file.name}">
                         <td><input class="form-check-input row-checkbox" type="checkbox"></td>
                         <td class="text-center">${index + 1}</td>
                         <td><i class="las la-database text-primary me-2"></i>${file.name}</td>
                         <td>${formatBytes(file.size)}</td>
                         <td>${formatDate(file.modified)}</td>
                         <td class="text-end">${actions}</td>
                       </tr>
                       <tr class="sql-viewer-row"><td colspan="6" class="sql-viewer-cell"></td></tr>`;
          tbody.append(row);
        });
        $('[data-bs-toggle="tooltip"]').tooltip();
      };

      const updateSortIcons = () => {
        const th = $(`thead th[data-sort="${currentSort.column}"]`);
        $('thead th.sortable .sort-icon').removeClass('la-sort-up la-sort-down').addClass('la-sort');
        th.find('.sort-icon').removeClass('la-sort').addClass(currentSort.direction === 'asc' ? 'la-sort-up' : 'la-sort-down');
      };

      function updateBulkActions() {
        const isRecycleTab = $('#pills-recycled-tab').hasClass('active');
        const selectedBackups = $('#backups-tbody .row-checkbox:checked').length;
        const selectedRecycled = $('#recycled-tbody .row-checkbox:checked').length;
        $('#backup-selected-count').text(`${selectedBackups} item(s) selected`);
        $('#bulk-actions-backups').css('display', selectedBackups > 0 && !isRecycleTab ? 'flex' : 'none');
        $('#recycled-selected-count').text(`${selectedRecycled} item(s) selected`);
        $('#bulk-actions-recycled').css('display', selectedRecycled > 0 && isRecycleTab ? 'flex' : 'none');
      }

      const updateUI = () => {
        renderTable(allBackups, 'backups-table');
        renderTable(allRecycled, 'recycled-table');
        $('#backup-count-badge').text(allBackups.length);
        $('#recycled-count-badge').text(allRecycled.length);
        const isRecycleTab = $('#pills-recycled-tab').hasClass('active');
        $('#db-restore-all-btn').toggleClass('d-none', !isRecycleTab || allRecycled.length === 0);
        $('#db-empty-bin-btn').toggleClass('d-none', !isRecycleTab || allRecycled.length === 0);
        updateSortIcons();
        updateBulkActions();
      };

      function loadBackupStats() {
        $.getJSON('ajax/database_handler.php?action=get_backup_stats', (res) => {
          if (res.success) {
            $('#last-backup-ago').text(res.stats.last_backup_ago);
            const chartCtx = document.getElementById('backup-chart');
            if (!chartCtx) return;
            if (backupChart) backupChart.destroy();
            backupChart = new Chart(chartCtx.getContext('2d'), {
              type: 'bar',
              data: {
                labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'],
                datasets: [{
                  label: `Backups in ${new Date().getFullYear()}`,
                  data: res.stats.by_month,
                  backgroundColor: 'rgba(34, 197, 173, 0.5)',
                  borderColor: 'rgba(34, 197, 173, 1)',
                  borderWidth: 1,
                  borderRadius: 4
                }]
              },
              options: {
                responsive: true,
                maintainAspectRatio: false,
                scales: { y: { beginAtZero: true, ticks: { stepSize: 1 } } },
                plugins: { legend: { display: false }, tooltip: { displayColors: false } }
              }
            });
          }
        });
      }

      const loadBackups = () => {
        return $.getJSON('ajax/database_handler.php?action=get_backups', (res) => {
          if (res.success) {
            allBackups = res.backups;
            allRecycled = res.recycled;
            const activeSize = allBackups.reduce((s, f) => s + f.size, 0);
            const recycledSize = allRecycled.reduce((s, f) => s + f.size, 0);
            $('#active-backup-size').text(formatBytes(activeSize));
            $('#recycled-backup-size').text(formatBytes(recycledSize));
            $('#total-backup-size').text(formatBytes(activeSize + recycledSize));
            updateUI();
          } else {
            toastr.error('Could not load backup files.');
          }
        }).fail(() => toastr.error('Server error.'));
      };

      const handleFileAction = (action, data, sourceElement = null) => {
        const performAction = () => {
          $.post('ajax/database_handler.php', { action: action, ...data }, (res) => {
            if (res.success) {
              toastr.success(res.message);
              loadBackups();
            } else {
              toastr.error(res.message || 'Action failed.');
            }
          }, 'json').fail(() => toastr.error('Server error.'));
        };
        if (sourceElement && $(sourceElement).closest('tr').length) {
          $(sourceElement).closest('tr').addClass('fading-out');
          setTimeout(performAction, 400);
        } else {
          performAction();
        }
      };

      const createBackup = (btn) => {
        const icon = btn.find('i');
        btn.prop('disabled', true);
        icon.addClass('fa-spin');
        $.post('db-backup.php', (res) => {
          if (res.success) {
            toastr.success(res.message);
            if (typeof loadBackups === 'function' && $('#databaseTab').is(':visible')) {
              loadBackups();
            }
            loadBackupStats();
          } else {
            toastr.error(res.message || 'Backup failed.');
          }
        }, 'json').fail(() => toastr.error('Server error.')).always(() => {
          icon.removeClass('fa-spin');
          btn.prop('disabled', false);
        });
      };

      $('#create-backup-btn, #header-create-backup-btn').on('click', function() {
        createBackup($(this));
      });

      $('#db-search').on('keyup', updateUI);
      $('#db-refresh-btn').on('click', loadBackups);
      $('#db-sort-by').on('change', function() {
        const [column, direction] = $(this).val().split('_');
        currentSort = { column, direction };
        updateUI();
      });

      function setupDeleteModal(files, from, sourceElement) {
        const isSingle = files.length === 1;
        $('#deleteModalBodyText').text(isSingle ? 'Are you sure you want to delete this backup?' : `Are you sure you want to delete ${files.length} selected backups?`);
        $('#deleteModalFilenameContainer').toggle(isSingle);
        if (isSingle) $('#deleteModalFilename').text(files[0]);

        $('#permanentDeleteHint').text(from === 'backup' ? 'If unchecked, the file(s) will be moved to the recycle bin.' : 'This action is irreversible.');
        $('#permanentDeleteCheck').prop('checked', false).prop('disabled', from !== 'backup').trigger('change');
        if (from !== 'backup') $('#permanentDeleteCheck').prop('checked', true).trigger('change');

        $('#confirmDeleteBtnDb').off('click').on('click', function() {
          const isPermanent = $('#permanentDeleteCheck').is(':checked');
          const action = (isPermanent && from === 'backup') || from === 'recycle_bin' ? 'delete_permanently' : 'move_to_recycle_bin';
          handleFileAction(action, { files, from }, sourceElement);
          deleteModal.hide();
        });
        deleteModal.show();
      }

      $('#databaseTab').on('click', '.delete-btn', function() {
        setupDeleteModal([$(this).data('filename')], 'backup', this);
      });

      $('#databaseTab').on('click', '.perm-delete-btn', function() {
        setupDeleteModal([$(this).data('filename')], 'recycle_bin', this);
      });

      $('#bulk-delete-btn').on('click', function() {
        const files = $('#backups-tbody .row-checkbox:checked').closest('tr').map((_, el) => $(el).data('filename')).get();
        if (files.length > 0) setupDeleteModal(files, 'backup', null);
      });

      $('#bulk-perm-delete-btn').on('click', function() {
        const files = $('#recycled-tbody .row-checkbox:checked').closest('tr').map((_, el) => $(el).data('filename')).get();
        if (files.length > 0) setupDeleteModal(files, 'recycle_bin', null);
      });

      $('#permanentDeleteCheck').on('change', function() {
        const btn = $('#confirmDeleteBtnDb');
        if ($(this).is(':checked')) {
          btn.removeClass('btn-primary').addClass('btn-danger').html('<i class="las la-exclamation-triangle me-1"></i>Delete Permanently');
        } else {
          btn.removeClass('btn-danger').addClass('btn-primary').text('Proceed');
        }
      });

      $('#databaseTab').on('click', '.view-btn', function() {
        const row = $(this).closest('tr');
        const viewerRow = row.next('.sql-viewer-row');
        const cell = viewerRow.find('.sql-viewer-cell');
        if (viewerRow.is(':visible')) {
          viewerRow.slideUp(300);
        } else {
          $('.sql-viewer-row').not(viewerRow).slideUp(300).find('.sql-viewer-cell').empty();
          if (cell.is(':empty')) {
            const from = row.closest('table').attr('id').includes('recycled') ? 'recycle_bin' : 'backup';
            cell.html('<div class="p-3 text-center"><span class="spinner-border"></span></div>');
            viewerRow.slideDown(300);
            $.getJSON(`ajax/database_handler.php?action=get_backup_content&file=${row.data('filename')}&from=${from}`, (res) => {
              if (res.success) {
                const escapedContent = res.content.replace(/</g, "&lt;").replace(/>/g, "&gt;");
                cell.html(`<div class="sql-viewer-content">
                             <div class="sql-viewer-header">
                               <div class="actions">
                                 <button class="btn btn-sm copy-sql-btn" data-bs-toggle="tooltip" title="Copy SQL"><i class="las la-clipboard"></i></button>
                                 <button class="btn btn-sm close-viewer-btn" data-bs-toggle="tooltip" title="Close"><i class="las la-times"></i></button>
                               </div>
                               <span class="filename">${row.data('filename')}</span>
                             </div>
                             <pre class="line-numbers language-sql"><code>${escapedContent}</code></pre>
                           </div>`);
                Prism.highlightAllUnder(cell[0]);
                $('[data-bs-toggle="tooltip"]').tooltip();
              } else {
                cell.html('<div class="p-3 text-danger">Error loading file.</div>');
              }
            }).fail(() => cell.html('<div class="p-3 text-danger">Server request failed.</div>'));
          } else {
            viewerRow.slideDown(300);
          }
        }
      });

      $('#databaseTab').on('click', '.copy-sql-btn', function() {
        const code = $(this).closest('.sql-viewer-content').find('code').text();
        navigator.clipboard.writeText(code).then(() => toastr.success('SQL copied!'), () => toastr.error('Failed to copy.'));
      });

      $('#databaseTab').on('click', '.close-viewer-btn', function() {
        $(this).closest('.sql-viewer-row').slideUp(300);
      });

      $('#databaseTab').on('click', '.restore-btn', function() {
        handleFileAction('restore_from_recycle_bin', { files: [$(this).data('filename')] }, this);
      });

      $('#db-empty-bin-btn').on('click', function() {
        handleFileAction('empty_recycle_bin', {}, null);
      });

      $('#db-restore-all-btn').on('click', function() {
        handleFileAction('restore_all', {}, null);
      });

      $('#bulk-restore-btn').on('click', function() {
        const files = $('#recycled-tbody .row-checkbox:checked').closest('tr').map((_, el) => $(el).data('filename')).get();
        handleFileAction('restore_from_recycle_bin', { files }, null);
      });

      $('#databaseTab').on('change', '.row-checkbox, #select-all-backups, #select-all-recycled', updateBulkActions);

      $('#select-all-backups').on('change', function() {
        $('#backups-tbody .row-checkbox').prop('checked', $(this).prop('checked')).trigger('change');
      });

      $('#select-all-recycled').on('change', function() {
        $('#recycled-tbody .row-checkbox').prop('checked', $(this).prop('checked')).trigger('change');
      });

      $('#databaseTab .nav-pills .nav-link').on('shown.bs.tab', function(event) {
        const targetId = $(event.target).data('bs-target');
        $('.file-management-controls').toggle(targetId !== '#pills-analytics');
        updateUI();
        $('#select-all-backups, #select-all-recycled').prop('checked', false);
      });

      loadBackupStats();

      if ($('#database-tab-link').hasClass('active')) {
        loadBackups();
      }

      $('#database-tab-link').on('shown.bs.tab', () => {
        if (allBackups.length === 0 && allRecycled.length === 0) loadBackups();
      });
    });